@app.get("/api/gallery")
def gallery(
    request: Request,
    extension: str | None = Query(default=None),
    limit: int = Query(default=50, ge=1, le=200),
):
    items = []
    wanted_extension = extension.lower().strip() if extension else None
    if wanted_extension and not wanted_extension.startswith("."):
        wanted_extension = f".{wanted_extension}"

    base_url = get_base_url(request)

    for path in sorted(OUTPUT_DIR.iterdir(), key=lambda p: p.stat().st_mtime, reverse=True):
        if not path.is_file():
            continue

        suffix = path.suffix.lower()
        if wanted_extension and suffix != wanted_extension:
            continue

        items.append(
            {
                "name": path.name,
                "size_bytes": path.stat().st_size,
                "modified_ts": path.stat().st_mtime,
                "url": f"/api/file/{path.name}",
                "absolute_url": f"{base_url}/api/file/{path.name}" if base_url else f"/api/file/{path.name}",
                "extension": suffix,
            }
        )

    return {"items": items[:limit], "count": len(items[:limit]), "base_url": base_url}

